// =============================================
// App.js - The main React component
//
// This file ties everything together:
// - Sets up the React Flow canvas
// - Manages state (prompt, response, loading)
// - Handles the "Run Flow" and "Save" button clicks
// =============================================

import React, { useState, useCallback } from "react";
import {
  ReactFlow,
  Background,
  Controls,
  addEdge,
  useNodesState,
  useEdgesState,
} from "@xyflow/react";
import "@xyflow/react/dist/style.css";

import InputNode from "./InputNode";
import ResultNode from "./ResultNode";
import HistoryPanel from "./HistoryPanel";

// Tell React Flow about our custom node types
const nodeTypes = {
  inputNode: InputNode,
  resultNode: ResultNode,
};

function App() {
  // ----- STATE -----
  const [prompt, setPrompt] = useState("");           // User's typed prompt
  const [response, setResponse] = useState("");       // AI's response
  const [isLoading, setIsLoading] = useState(false);  // True while calling AI
  const [statusMsg, setStatusMsg] = useState("");     // "Saved!" message
  const [showHistory, setShowHistory] = useState(false); // Toggle history panel

  // ----- REACT FLOW SETUP -----
  // Define the two nodes that appear on the canvas
  // Note: We pass data as functions so nodes can read the latest state
  const initialNodes = [
    {
      id: "input-node",
      type: "inputNode",        // Uses our custom InputNode component
      position: { x: 80, y: 150 },
      data: {
        prompt: "",
        onPromptChange: () => {},  // Will be set properly below
      },
    },
    {
      id: "result-node",
      type: "resultNode",       // Uses our custom ResultNode component
      position: { x: 520, y: 150 },
      data: {
        response: "",
        isLoading: false,
      },
    },
  ];

  // Define the edge (line) connecting the two nodes
  const initialEdges = [
    {
      id: "edge-1",
      source: "input-node",    // Line starts at input node
      target: "result-node",   // Line ends at result node
      animated: true,           // Makes the line animated (dashed flow)
      style: { stroke: "#38bdf8", strokeWidth: 2 },
    },
  ];

  const [nodes, setNodes, onNodesChange] = useNodesState(initialNodes);
  const [edges, setEdges, onEdgesChange] = useEdgesState(initialEdges);

  // Allow users to create new connections by dragging
  const onConnect = useCallback(
    (params) => setEdges((eds) => addEdge(params, eds)),
    [setEdges]
  );

  // ----- UPDATE NODES WHEN STATE CHANGES -----
  // Whenever prompt, response, or loading changes,
  // we update the node data so the nodes re-render.
  React.useEffect(() => {
    setNodes((prevNodes) =>
      prevNodes.map((node) => {
        if (node.id === "input-node") {
          return {
            ...node,
            data: {
              prompt: prompt,
              // This function is called when user types in the textarea
              onPromptChange: (newPrompt) => setPrompt(newPrompt),
            },
          };
        }
        if (node.id === "result-node") {
          return {
            ...node,
            data: {
              response: response,
              isLoading: isLoading,
            },
          };
        }
        return node;
      })
    );
  }, [prompt, response, isLoading]); // Re-run whenever these change

  // ----- RUN FLOW HANDLER -----
  // Called when user clicks "Run Flow"
  const handleRunFlow = async () => {
    if (!prompt.trim()) {
      alert("Please type a prompt first!");
      return;
    }

    setIsLoading(true);
    setResponse(""); // Clear old response
    setStatusMsg("");

    try {
      // Send the prompt to our Express backend
      // (The "proxy" in package.json forwards this to http://localhost:5000)
      const res = await fetch("/api/ask-ai", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ prompt }),
      });

      const data = await res.json();

      if (data.error) {
        setResponse("Error: " + data.error);
      } else {
        setResponse(data.response);
      }
    } catch (err) {
      setResponse("Failed to connect to the server. Is the backend running?");
    } finally {
      setIsLoading(false);
    }
  };

  // ----- SAVE HANDLER -----
  // Called when user clicks "Save"
  const handleSave = async () => {
    if (!prompt || !response) {
      alert("Run the flow first before saving!");
      return;
    }

    try {
      const res = await fetch("/api/save", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ prompt, response }),
      });

      const data = await res.json();

      if (data.message) {
        setStatusMsg("✅ Saved to database!");
        // Clear the message after 3 seconds
        setTimeout(() => setStatusMsg(""), 3000);
      }
    } catch (err) {
      setStatusMsg("❌ Failed to save.");
    }
  };

  // ----- RENDER -----
  return (
    <div className="app-container">
      {/* Top Toolbar */}
      <div className="toolbar">
        <h1>⚡ AI Flow</h1>

        <button
          className="btn btn-run"
          onClick={handleRunFlow}
          disabled={isLoading}
        >
          {isLoading ? "Running..." : "▶ Run Flow"}
        </button>

        <button
          className="btn btn-save"
          onClick={handleSave}
          disabled={!response || isLoading}
        >
          💾 Save
        </button>

        <button
          className="btn btn-history"
          onClick={() => setShowHistory(!showHistory)}
        >
          📚 History
        </button>

        {/* Show "Saved!" message */}
        {statusMsg && <span className="status-msg">{statusMsg}</span>}
      </div>

      {/* React Flow Canvas */}
      <div className="flow-canvas">
        <ReactFlow
          nodes={nodes}
          edges={edges}
          onNodesChange={onNodesChange}
          onEdgesChange={onEdgesChange}
          onConnect={onConnect}
          nodeTypes={nodeTypes}
          fitView
        >
          {/* Grid background */}
          <Background color="#1e293b" gap={20} />
          {/* Zoom and pan controls */}
          <Controls />
        </ReactFlow>
      </div>

      {/* History Sidebar (shown/hidden) */}
      {showHistory && (
        <HistoryPanel onClose={() => setShowHistory(false)} />
      )}
    </div>
  );
}

export default App;
